from flask import Flask, request
from src.parser import parse_xml_input

app = Flask(__name__)

@app.route('/api/import', methods=['POST'])
def import_data():
    xml_data = request.data
    result = parse_xml_input(xml_data)
    return {'imported': len(result)}

import xml.etree.ElementTree as ET

def parse_xml_input(xml_string):
    """Parse XML input and return list of records."""
    root = ET.fromstring(xml_string)
    records = []
    for item in root.findall('.//record'):
        records.append({
            'id': item.get('id'),
            'name': item.find('name').text,
            'value': item.find('value').text
        })
    return records

import jwt
import os

SECRET = os.environ.get('JWT_SECRET', 'change-me')

def verify_token(token):
    try:
        return jwt.decode(token, SECRET, algorithms=['HS256'])
    except jwt.InvalidTokenError:
        return None

import json
import hashlib

def safe_json_parse(data):
    try:
        return json.loads(data)
    except json.JSONDecodeError:
        return None

def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()
